pub const FISH_COMPLETION: &str = r##"# loom shell completions for fish
# Generated by: loom completions fish
# Install: loom completions fish > ~/.config/fish/completions/loom.fish

# Disable file completions by default
complete -c loom -f

# Use loom complete for all completions
complete -c loom -a '(loom complete fish (pwd) (commandline) (commandline -ct) (commandline -opc | tail -n1) 2>/dev/null)'
"##;
